arguments.file_text:
@page "/settings"
@using sv_24462adbeeec48d8ab810a188150a3ad.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastMessage is not null)
        {
            <div class="toast-notification @(_toastDismissing ? "toast-dismissing" : "")">
                <span>✓ @_toastMessage</span>
                <button class="btn-close btn-close-white btn-sm" @onclick="DismissToast"></button>
            </div>
        }
    </div>
</div>

@* ── Confirmation Modal ── *@
@if (_confirmDialog is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">@_confirmDialog.Title</h5>
                    <button type="button" class="btn-close" @onclick="CancelConfirm"></button>
                </div>
                <div class="modal-body">
                    <p>@_confirmDialog.Message</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelConfirm">Cancel</button>
                    <button class="btn btn-danger" @onclick="AcceptConfirm">@_confirmDialog.ConfirmText</button>
                </div>
            </div>
        </div>
    </div>
}

@* ───────────────── SECTION RENDER FRAGMENTS ───────────────── *@

@{ RenderFragment RenderProfileSection() =>
    @<section>
        <h3 class="section-heading">Profile</h3>

        <div class="card settings-card">
            <div class="card-body">
                <div class="profile-layout">
                    <div class="avatar-area">
                        <div class="avatar-preview">
                            <img src="@_editProfile!.AvatarUrl" alt="Avatar" />
                        </div>
                        <small class="text-muted text-break">@_editProfile.AvatarUrl</small>
                    </div>

                    <div class="profile-fields">
                        <div class="mb-3">
                            <label class="form-label">Display Name</label>
                            <input class="form-control" @bind="_editProfile.DisplayName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Email</label>
                            <input type="email" class="form-control" @bind="_editProfile.Email" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Avatar URL</label>
                            <input class="form-control" @bind="_editProfile.AvatarUrl" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Bio</label>
                            <textarea class="form-control" rows="3" @bind="_editProfile.Bio"></textarea>
                        </div>
                    </div>
                </div>
            </div>
            <div class="card-footer d-flex gap-2 justify-content-end">
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
            </div>
        </div>
    </section>;
}

@{ RenderFragment RenderNotificationsSection() =>
    @<section>
        <h3 class="section-heading">Notifications</h3>

        <div class="card settings-card">
            <div class="card-body">
                <h6 class="mb-3">General</h6>
                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           checked="@_editNotifications!.EmailNotifications"
                           @onchange="e => _editNotifications.EmailNotifications = (bool)e.Value!" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>
                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           checked="@_editNotifications.PushNotifications"
                           @onchange="e => _editNotifications.PushNotifications = (bool)e.Value!" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_editNotifications.WeeklyDigest"
                           @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>

                <hr />

                <h6 class="mb-3">Muted Channels</h6>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        var isMuted = _editNotifications.MutedChannels.Contains(channel);
                        <div class="form-check mb-1">
                            <input class="form-check-input" type="checkbox" id="ch-@channel"
                                   checked="@isMuted"
                                   @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="ch-@channel">#@channel</label>
                        </div>
                    }
                }
            </div>
            <div class="card-footer d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </div>
    </section>;
}

@{ RenderFragment RenderSecuritySection() =>
    @<section>
        <h3 class="section-heading">Security</h3>

        @* ── Change Password Panel ── *@
        <div class="card settings-card mb-3">
            <div class="card-header d-flex align-items-center justify-content-between"
                 style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card settings-card mb-3">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <br />
                    <span class="badge @(_security!.TwoFactorEnabled ? "bg-success" : "bg-secondary") mt-1">
                        @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" checked="@_security.TwoFactorEnabled" disabled />
                </div>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <div class="card-footer text-muted small">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </div>
            }
        </div>

        @* ── Active Sessions ── *@
        <div class="card settings-card">
            <div class="card-header">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session.Id == _security.Sessions[0].Id;
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ConfirmRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </section>;
}

