@page "/settings"
@using sv_24462adbeeec48d8ab810a188150a3ad.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main Content -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastMessage is not null)
        {
            <div class="toast-notification @(_toastDismissing ? "toast-dismissing" : "")">
                <span>✓ @_toastMessage</span>
                <button class="btn-close btn-close-white btn-sm" @onclick="DismissToast"></button>
            </div>
        }
    </div>
</div>

@* ── Confirmation Modal ── *@
@if (_confirmDialog is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">@_confirmDialog.Title</h5>
                    <button type="button" class="btn-close" @onclick="CancelConfirm"></button>
                </div>
                <div class="modal-body">
                    <p>@_confirmDialog.Message</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelConfirm">Cancel</button>
                    <button class="btn btn-danger" @onclick="AcceptConfirm">@_confirmDialog.ConfirmText</button>
                </div>
            </div>
        </div>
    </div>
}

