@{ RenderFragment RenderSecuritySection() =>
    @<section>
        <h3 class="section-heading">Security</h3>

        @* ── Change Password Panel ── *@
        <div class="card settings-card mb-3">
            <div class="card-header d-flex align-items-center justify-content-between"
                 style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card settings-card mb-3">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <br />
                    <span class="badge @(_security!.TwoFactorEnabled ? "bg-success" : "bg-secondary") mt-1">
                        @(_security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" checked="@_security.TwoFactorEnabled" disabled />
                </div>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <div class="card-footer text-muted small">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </div>
            }
        </div>

        @* ── Active Sessions ── *@
        <div class="card settings-card">
            <div class="card-header">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session.Id == _security.Sessions[0].Id;
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ConfirmRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </section>;
}

@{ RenderFragment RenderAppearanceSection() =>
    @<section>
        <h3 class="section-heading">Appearance</h3>

        <div class="card settings-card mb-3">
            <div class="card-body">
                <h6 class="mb-3">Theme</h6>
